if (!function_exists('e')) {
    function e(string $metin): string
    {
        return htmlspecialchars($metin, ENT_QUOTES | ENT_HTML5, 'UTF-8');
    }
}
if (!function_exists('sayf')) {
    function sayf(string $yol): string
    {
        return rtrim(APP_URL, '/') . '/' . ltrim($yol, '/');
    }
}
if (!function_exists('aktifMi')) {
    function aktifMi(string $sayfa): string
    {
        $mevcutSayfa = basename($_SERVER['SCRIPT_FILENAME'] ?? '');
        return $mevcutSayfa === $sayfa ? ' aktif' : '';
    }
}
if (!function_exists('rolAdi')) {
    function rolAdi(string $rol): string
    {
        return match ($rol) {
            'admin' => 'Sistem Yöneticisi',
            'eczane' => 'Eczane / Kurum',
            'kullanici' => 'Kullanıcı',
            default => 'Misafir',
        };
    }
}
if (!function_exists('flashIkon')) {
    function flashIkon(string $tip): string
    {
        return match ($tip) {
            'basari' => 'check-circle',
            'tehlike' => 'alert-circle',
            'uyari' => 'alert-triangle',
            default => 'info',
        };
    }
}
if (!function_exists('initialsAvatar')) {
    function initialsAvatar(string $adSoyad): string
    {
        $parcalar = explode(' ', trim($adSoyad));
        $ils = mb_substr($parcalar[0] ?? 'U', 0, 1, 'UTF-8');
        if (count($parcalar) > 1) {
            $ils .= mb_substr(end($parcalar), 0, 1, 'UTF-8');
        }
        return mb_strtoupper($ils, 'UTF-8');
    }
}
