if (!function_exists('isAjax')) {
    function isAjax(): bool
    {
        return !empty($_SERVER['HTTP_X_REQUESTED_WITH']) &&
            strtolower($_SERVER['HTTP_X_REQUESTED_WITH']) === 'xmlhttprequest';
    }
}
if (!function_exists('apiCevap')) {
    function apiCevap(bool $basari, string $mesaj = '', array $ekstra = [], int $kod = 200): never
    {
        if (!headers_sent()) {
            header('Content-Type: application/json; charset=utf-8');
            http_response_code($kod);
        }
        echo json_encode(array_merge(['basari' => $basari, 'mesaj' => $mesaj], $ekstra), JSON_UNESCAPED_UNICODE);
        exit;
    }
}
if (!function_exists('csrf_token')) {
    function csrf_token(): string
    {
        if (session_status() === PHP_SESSION_NONE)
            session_start();
        if (empty($_SESSION['csrf_token'])) {
            $_SESSION['csrf_token'] = bin2hex(random_bytes(32));
        }
        return $_SESSION['csrf_token'];
    }
}
if (!function_exists('csrf_field')) {
    function csrf_field(): string
    {
        return '<input type="hidden" name="csrf_token" value="' . csrf_token() . '">';
    }
}
if (!function_exists('csrf_verify')) {
    function csrf_verify(): void
    {
        if ($_SERVER['REQUEST_METHOD'] === 'POST') {
            $token = $_POST['csrf_token'] ?? '';
            if (!$token || $token !== ($_SESSION['csrf_token'] ?? '')) {
                if (isAjax()) {
                    apiCevap(false, 'CSRF doğrulama hatası. Lütfen sayfayı yenileyin.', [], 403);
                } else {
                    die('CSRF doğrulama hatası. Lütfen sayfayı yenileyin.');
                }
            }
        }
    }
}
