function bildirimGonder($kullaniciId, $baslik, $mesaj, $tip = 'info', $kategori = 'sistem', $eylemler = null)
{
    try {
        $stmt = db()->prepare("
            INSERT INTO bildirimler (kullanici_id, baslik, mesaj, tip, kategori, eylemler) 
            VALUES (?, ?, ?, ?, ?, ?)
        ");
        return $stmt->execute([
            $kullaniciId,
            $baslik,
            $mesaj,
            $tip,
            $kategori,
            $eylemler ? json_encode($eylemler) : null
        ]);
    } catch (PDOException $e) {
        return false;
    }
}